SET NAMES utf8mb4;

CREATE TABLE `inventory_logs`  (
  `id` int NOT NULL AUTO_INCREMENT COMMENT 'ТБџтЇИсЃГсѓ░ID',
  `item` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL COMMENT 'жаЁуЏ«№╝ѕТЮљТќЎТБџтЇИ/жЃетЊЂТБџтЇИ/УБйтЊЂТБџтЇИ№╝Ѕ',
  `product_cd` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL COMMENT 'УБйтЊЂ/ТЮљТќЎ/жЃетЊЂCD',
  `product_name` varchar(200) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL COMMENT 'УБйтЊЂ/ТЮљТќЎ/жЃетЊЂтљЇ',
  `process_cd` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL COMMENT 'тиЦуеІCD',
  `log_date` date NOT NULL COMMENT 'ТЌЦС╗ў',
  `log_time` time NOT NULL COMMENT 'ТЎѓжќЊ',
  `hd_no` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL COMMENT 'HDNo',
  `pack_qty` int NULL DEFAULT NULL COMMENT 'тЁЦТЋ░№╝ѕу«▒/сЃЉсЃЃсѓ»тЇўСйЇ№╝Ѕ',
  `case_qty` int NULL DEFAULT NULL COMMENT 'сѓ▒сЃ╝сѓ╣ТЋ░',
  `quantity` int NOT NULL COMMENT 'ТЋ░жЄЈ',
  `remarks` text CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL COMMENT 'ТІЁтйЊУђЁCDсЂфсЂЕ',
  `created_at` datetime NULL DEFAULT CURRENT_TIMESTAMP COMMENT 'СйюТѕљТЌЦТЎѓ',
  `updated_at` datetime NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT 'ТЏ┤Тќ░ТЌЦТЎѓ',
  PRIMARY KEY (`id`) USING BTREE,
  INDEX `idx_log_date`(`log_date` ASC) USING BTREE,
  INDEX `idx_process_date`(`process_cd` ASC, `log_date` ASC) USING BTREE,
  INDEX `idx_item_date_time`(`item` ASC, `log_date` ASC, `log_time` ASC) USING BTREE,
  INDEX `idx_dup_key`(`item` ASC, `product_cd` ASC, `product_name` ASC, `log_date` ASC, `log_time` ASC) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 12378 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_0900_ai_ci COMMENT = 'ТБџтЇИсЃГсѓ░' ROW_FORMAT = DYNAMIC;
